var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"거기까지다, 멈춰.","JPN":"そこまでだ、止まれ。","ENG":"That's as far as you'll go. Enough.","TWN":"住手，到此為止。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"소대장! 어떻게 여기에?","JPN":"小隊長！　なんでここに？","ENG":"Commander! How did you get here?","TWN":"小隊長？你怎麼會在這裡？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"스승님만이 아니군요. 당신은……","JPN":"師匠だけではありませんね、あなたは……","ENG":"It's not just you, Master. But you…","TWN":"師父不是自己一個喔？還有你……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 저희가 아주 늦지는 않은 모양이네요.","JPN":"ハハ、僕たちギリギリ間に合ったようですね。","ENG":"Haha, looks like we haven't missed the entire show.","TWN":"哈哈～看起來我們還不算太晚啦。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"주시윤, 다친 곳은 없나?","JPN":"アキヤマ、ケガはないか？","ENG":"Are you unhurt, Joo Shiyoon?","TWN":"周時雲，你有受傷嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"아니, 잠깐…… 그 칼집은 어디선 난 거지?","JPN":"いや待て……その鞘はどこで手に入れた？","ENG":"Hang on… Where did you get that scabbard?","TWN":"等等……那個劍鞘是哪來的？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너 대체 여기서 무슨 일이 있었던 거냐?","JPN":"ここでいったい何があったんだ？","ENG":"What happened to you here?","TWN":"你在這裡到底發生了什麼事？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"나중에 말씀드릴게요. 여기서 얘기하기엔 좀 길어져서요.","JPN":"それは後にしましょう。ここで話すにはちょっと長くなりそうですので。","ENG":"I'll tell you all about it later. It's a long story.","TWN":"說來話長，之後再跟師父報告。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금은 저 황태자라는 분과의 문제부터 해결하는 게 어떨까요?","JPN":"今はあの皇太子という方との問題から解決したほうがよさそうです。","ENG":"For now, why don't we sort out this issue with that Crown Prince gentleman?","TWN":"現在先解決我跟那個叫皇太子的之間的問題好嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……좋다.","JPN":"……いいだろう。","ENG":"...Very well.","TWN":"……好。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"자세한 보고는 회사로 복귀한 후에 듣도록 하지.","JPN":"詳しい報告は会社に戻った後に聞こう。","ENG":"You can debrief me in detail once we get back to the office.","TWN":"等回到公司你再跟我報告清楚。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네 말대로 지금은 저 녀석부터 처리해야 할 것 같으니까.","JPN":"今はお前の言うとおり、あいつを対処したほうがよさそうだ。","ENG":"Like you said, I think we'll have to deal with this guy first.","TWN":"現在就照你說的先處理那傢伙吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이것 참, 오늘은 무대에 난입하는 관객들이 많군.","JPN":"やれやれ、今日は舞台に乱入する観客が多いな。","ENG":"My, my. We have too many hecklers here today.","TWN":"真是的，今天還真多觀眾干擾演出。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이번 세계의 야만인들은 참으로 교양이 부족하단 말이야.","JPN":"この世界の野蛮人たちは実に教養が足りないようだ。","ENG":"These barbarians in this world simply have no class, I tell you.","TWN":"這次的世界好多沒教養的野蠻人。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……쓸데없는 경고겠지만, 일단은 말해 두지.","JPN":"……余計な警告だろうが、一応言っておこう。","ENG":"…I know this will fall on deaf ears, but I'll say it anyway.","TWN":"……雖然你耳朵很硬，但我還是說一下。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"난 내 멍청한 제자 놈을 구하러 온 거다.","JPN":"私はあのマヌケな弟子を助けに来た。","ENG":"I'm just here to rescue my stupid apprentice.","TWN":"我來是要救我的笨徒弟，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네가 우릴 가로막지 않는다면 굳이 싸우고 싶은 생각은 없어.","JPN":"お前が私たちの邪魔をしないなら、あえて戦うつもりはない。","ENG":"If you won't stand in our way, we don't have to fight.","TWN":"只要你不擋路，我沒有要動手的意思。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……그것 참 그대답지 않은 말이로군, 발키리.","JPN":"……それはまったく貴様らしくない発言だな、ヴァルキリー。","ENG":"…That does not sound like thee at all, Valkyrie.","TWN":"……這真不像你會說的話呢？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"분명 예전에는 좀 더 적극적인 성격이었을 텐데?","JPN":"確か以前はもっと積極的な性格だったはずだが？","ENG":"Were thou not more aggressively committed to combat long time ago?","TWN":"以前的你明明沒這麼消極應戰的？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아, 힘을 사용하다가 게임이 시작되는 것을 걱정하는 건가?","JPN":"ああ、力を行使してゲームが始まることを懸念しているのか？","ENG":"Ah, art thou worried the game may begin if thou exert thyself too much?","TWN":"哦～你是怕使用力量後會啟動遊戲嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이해할 수가 없군. 이미 금이 가 버린 제방이다. 무너지는 것은 필연이야.","JPN":"理解できんな。すでにヒビが入った堤防だ。崩れるのは必然である。","ENG":"I don't understand. This dam has already been fractured. It is bound to break down.","TWN":"我真搞不懂，防護牆都已經出現龜裂，倒塌也只是時間問題而已。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"왜 그리 허망한 꿈에 집착하는 거지?","JPN":"どうしてそこまでして虚しい夢に執着する？","ENG":"Why then dost thou chase after such empty dreams?","TWN":"為何要執著於那個不切實際的夢呢？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……이쪽은 넷이다. 설마 승산이 있다고 생각하는 건가?","JPN":"……こちらは4人だ。まさか勝算があるとでも？","ENG":"…There're four of us here. Do you really think you stand a chance?","TWN":"……我們有四個人，你覺得你有勝算嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"예전부터 그대와는 꼭 한 번 자웅을 겨뤄보고 싶었지.","JPN":"以前から貴様とは雌雄を決したいと思っていた。","ENG":"I've always desired to test my mettle against thee.","TWN":"我從以前就很想跟你分個高下，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"지금의 녹슬어버린 그대라면, 그 정도의 핸디캡은 아주 적절하다고 생각되는군.","JPN":"今の錆びてしまった貴様なら、それぐらいのハンデは適切だと思うが。","ENG":"Given how rusty thou hast grown, I suppose that will suffice as a handicap.","TWN":"加上你現在這副怯弱的樣子，弱點應該也不少，我未必會輸。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그만두세요.","JPN":"やめてください。","ENG":"Enough.","TWN":"住手。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너는……?","JPN":"お前は……？","ENG":"You…?","TWN":"你是……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"레이 선배?","JPN":"レイ先輩？","ENG":"Ray?","TWN":"雷伊前輩？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭐야 그 옷차림은?","JPN":"ど、どうしたのその服……？","ENG":"W-what's with that outfit?","TWN":"你那身裝備是怎麼回事？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……두 분 다 그만두세요.","JPN":"……二人ともおやめください。","ENG":"Both of you, that's enough.","TWN":"……兩位都請住手。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"싸움이라면 머지않아 질릴 만큼 하게 될 겁니다.","JPN":"戦いならもうじき、飽きるほどすることになるでしょう。","ENG":"You'll be doing plenty of fighting soon anyway.","TWN":"要打的話以後夠你們打的，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"지금부터 불필요한 피를 보는 건 제 뜻에도, 그대들의 뜻에도 맞지 않겠지요.","JPN":"今ここで余計な血を流すのは、僕の意思でもあなたたちの意思でもないはずです。","ENG":"Shedding unnecessary blood now fits neither my will nor yours.","TWN":"現在無論是我或是你們，都不需要流無謂的血。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"구원자님! 성역에서 돌아오셨군요!","JPN":"救世主様！　聖域から戻られたのですね！","ENG":"My Savior! You have returned from the sanctuary!","TWN":"救贖者大人！您從聖域回來了！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……감히 내게 명령을 한 건가? 평민 놈.","JPN":"……私に命令するのか？　平民の分際で？","ENG":"Thou dare order me around? A common peasant like thee?!","TWN":"……大膽刁民！你竟敢命令我？！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하! 아무리 그래도 구원자님께 그런 모욕적인 말씀은……!","JPN":"殿下！　いくらなんでも救世主様にそんな失礼なお言葉は……！","ENG":"Your Highness! I beg you not to insult the Savior in such a way…!","TWN":"殿下！對救贖者大人的用詞還請斟酌……！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"닥쳐라. 원래대로였다면 그 구원자라는 칭호도 저 흑색제복도 내 것이어야 했다.","JPN":"黙れ。本来ならその救世主という呼び名も、あの黒い礼装も私のものだったはずだ。","ENG":"Silence. Both that black garb and his title as Savior were meant to be mine.","TWN":"給我閉嘴！那個救贖者的稱號，還有那個黑色制服原本都是屬於我的！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"차라리 잘됐군. 지금 저 평민 놈의 목을 베어 버리면 저 흑색제복만은 내게 돌아오겠지.","JPN":"むしろよかったか。あの平民の首を落してしまえば黒い礼装だけは私の元に戻ってくるだろう。","ENG":"Very well. I suppose if I behead that fool now, I can at least retrieve that black uniform.","TWN":"現在這樣正好！等我砍下他的頭，那套黑色制服就會回到我身上來！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"태초의 용혈을 마신 라르고의 힘을 확인하기에 딱 적당한 상대가 되겠어.","JPN":"太古の龍血を吸ったラルゴの力を確かめるのにちょうどいい相手になりそうだな。","ENG":"He'll make the perfect opponent to test the power of Largo imbued with the first Dragon Blood.","TWN":"就拿你來實驗一下龍劍喝下原始龍血後的力量吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"불경합니다, 전하!","JPN":"不敬です、殿下！","ENG":"This is sacrilege, Your Highness!","TWN":"殿下萬萬不可！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그만두시죠, 전하.","JPN":"おやめください、殿下。","ENG":"That's enough, Your Highness.","TWN":"住手吧，殿下。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"지금 늑대의 문장을 가진 자들과 전투를 벌이는 것이 불필요하다고 판단한 건 저입니다.","JPN":"狼の紋章を持つ者と今戦うのは不要だと判断したのは私です。","ENG":"I'm the one who has determined that it is unnecessary to engage in combat with the bearers of the Seal of the Wolf.","TWN":"判斷現在不適合和對方交手的是我，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전 전하께서 직접 임명하신 구원기사단의 단장입니다.","JPN":"私は殿下が自ら任命した救世騎士団の団長です。","ENG":"Your Highness has personally appointed me to command the Knights of Redemption.","TWN":"而我是殿下親自任命的救贖騎士團隊長。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"설마 제 말도 듣지 않으실 겁니까?","JPN":"まさか私の話にも耳を傾けないおつもりでしょうか？","ENG":"Will you also dismiss my advice?","TWN":"難道您不聽我的話嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"……알렌 경.","JPN":"……バーミンガム卿。","ENG":"…Sir Allen.","TWN":"艾倫愛卿……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"쳇. 흥이 식어 버렸다.","JPN":"ちっ、つまらぬ展開になったな。","ENG":"Hmph. I've lost my interest.","TWN":"哼，興致都沒了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"먼저 돌아가겠다. 뒷일은 알아서 하도록.","JPN":"先に帰る。後は勝手にしろ。","ENG":"I'm leaving. Take care of the rest.","TWN":"我要先回去了，後面的事你們看著辦吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"나유빈 님. 당신께도 사과하겠습니다.","JPN":"イチノセさん。あなたにも謝罪します。","ENG":"Mr. Na Yubin. I owe you apology as well.","TWN":"羅瑜斌，我對你也很抱歉。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신과의 동맹을 깬 것은 제가 아니었지만…… 그들의 대표로서 제게도 책임이 있겠지요.","JPN":"あなたとの同盟を破ったのは私ではありませんが……代表として、私にも責任があるでしょう。","ENG":"Although it was not my intention to break our alliance… I bear part of the blame as their representative.","TWN":"雖然破壞合作協議的不是我……但身為他們的代表我也有責任。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이후로는 이런 일이 없을 것을 제 명예를 걸고 약속드리겠습니다.","JPN":"今後このようなことは二度とないと、私の名誉にかけて約束します。","ENG":"I swear upon my honor that this shall never happen again.","TWN":"我用我的名譽跟你保證，下不為例。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"확실히 구원자라는 이름답게 말이 통하는 분이시군요.","JPN":"確かに救世主という名にふさわしく、話がわかる方ですね。","ENG":"Ah, so that's why they call you the Savior. You can be reasoned with.","TWN":"真不愧是救贖者，說的話還聽得下去。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이런 진심 어린 사과를 듣고도 계속 화를 낼 수는 없지요.","JPN":"心のこもった謝罪を受けたのですから、ずっと怒っているわけにはいきません。","ENG":"I simply can't remain angry with a sincere apology like that.","TWN":"聽到你這麼真誠的道歉，怎麼還氣得下去呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신들이 우리와 했던 약속들만 지켜진다면 동맹은 계속 유지될 겁니다.","JPN":"あなたたちとこちらが交わした約束さえ守られるなら、同盟は継続しましょう。","ENG":"So long as you keep your promise, the alliance will stand.","TWN":"只要你們能夠繼續遵守我們之間的約定，那我也願意繼續維持合作關係。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……나유빈, 배신할 셈이냐?","JPN":"……イチノセ、裏切るのか？","ENG":"Are you going to betray us again, Yubin?","TWN":"……羅瑜斌，你想叛變嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저희는 처음부터 일시적인 동맹 아니었나요?","JPN":"僕たちは最初から一時的な同盟だったでしょう？","ENG":"Well, our alliance was temporary at best, wasn't it?","TWN":"但我們的合作關係不是本來就只是暫時的嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"시윤 군의 신병도 확보되었으니 각자 원래의 자리로 돌아가는 것뿐입니다.","JPN":"アキヤマ君の身柄も確保できましたし、それぞれの立場に戻るだけです。","ENG":"Now that you've secured Shiyoon, we're all going back to where we were before. That's all.","TWN":"既然已經確認時雲的人身安全，不是就該各自回到原本的位置嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아, 걱정마세요. 그렇다고 여기서 당장 저들 편을 들어 스승님과 싸울 만큼 염치 없지는 않으니까요.","JPN":"ああ、心配しないでください。だからといって、ここですぐ彼らの肩を持って師匠と戦うほど図々しい性格ではありません。","ENG":"Oh, don't worry. I'm not bullheaded enough to side with them and fight you right here.","TWN":"師父你放心，我還沒有不要臉到現在就立刻投奔敵營。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그리고 용병대장…… 아니, 지금은 힐데 님이라고 불러야겠군요.","JPN":"そして傭兵隊長……いや、今はヒルデ様ですね。","ENG":"As for you, Mercenary Captain… oh, I suppose I should call you Hilde now.","TWN":"還有，傭兵隊長……不對，現在該稱呼你希爾德才對。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신과 당신의 제자 분 역시 무사히 돌려보내드리겠습니다.","JPN":"あなたとあなたの弟子も無事に送らせていただきます。","ENG":"I will ensure safe passage back for you and your apprentice as well.","TWN":"我也會讓你和你的徒弟平安回去的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너…… 힘을 거의 다 회복했군.","JPN":"お前……力をほとんど回復しているな。","ENG":"You must have recovered almost all of your powers, then.","TWN":"看來……你的力量恢復得差不多了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"역시 방주의 힘으로 클리파 차원의 통로를 억지로 열어젖힌 건가?","JPN":"やはり箱舟の力でクリファ次元の通路を無理やりこじ開けたのか？","ENG":"Did you use the Ark to force open the passage to the Qlipha dimension?","TWN":"是利用方舟的力量強行打開逆卡巴拉次元的通道嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네. 마지막 순간에 방주가 정지해 버렸지만, 성역의 힘은 이 정도로도 충분합니다.","JPN":"はい、最後の瞬間に箱舟が停止してしまいましたが、聖域の力はこの程度でも十分です。","ENG":"Yes. Although the Ark stopped working at the very end, I've secured enough power for the sanctuary.","TWN":"是的，雖然方舟最後停止運作， 但這個程度的聖域力量已足夠，"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……다른 마왕들의 개입을 막기에도, 이 세계를 멸하기에도.","JPN":"……他の魔王たちの介入を防ぐのにも、この世を滅ぼすのにも。","ENG":"Enough to prevent the intervention of other Demon Lords… and enough to destroy this world.","TWN":"……足以阻止其他魔王的干預，也足以毀掉這個世界。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내가 가만히 있을 거라고 생각하는 건 아니겠지?","JPN":"私がそれを黙って見ていると思ってるのか？","ENG":"You don't expect me to do nothing about that, do you?","TWN":"你應該不會以為我會默默坐視這些事發生吧？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"물론입니다. 부디 최선을 다해서 절 막아주세요.","JPN":"いいえ、どうか最善を尽くして僕を止めてくださいね。","ENG":"Of course not. I pray you'll strive your utmost to stop me.","TWN":"當然知道，請你務必要盡全力阻止我。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신의 제자 분도 새로운 힘을 얻은 것 같으니 도움이 되겠지요.","JPN":"あなたの弟子も新しい力を得たようなので、力になるでしょう。","ENG":"I'm sure your apprentice will prove most helpful with his new powers now.","TWN":"你的徒弟也獲得了新的力量，應該多少會有點幫助。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 이 세계의 대적자조차 우리와 손잡고 있으니, 그리 쉽지는 않을 겁니다.","JPN":"しかし、この世界の敵対者も僕たちと手を組んでいますから、そう簡単ではないはずです。","ENG":"However, it won't be so easy, as even the Antagonist of this world has allied with us.","TWN":"但這個世界的敵對者也跟我們站在同一邊，應該會是場硬仗喔。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그렇게 생각한다면 차라리 그만두는 게……","JPN":"そう思っているならいっそやめたほうが……","ENG":"Maybe you should quit while you're ahead…","TWN":"你也知道是場硬戰嗎？那你勸你還是就此打住……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그럴 수는 없습니다. 전 맹세를 했으니까요.","JPN":"そうはいきません。僕は誓ったのです。","ENG":"I'm afraid that cannot be. I've already sworn an oath.","TWN":"當然不行，畢竟是發過誓的。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"대체 아까부터 무슨 소릴 하는 거야?","JPN":"いったいさっきから何の話？","ENG":"What are you guys babbling about?!","TWN":"你們到底在說什麼？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"레이 선배! 대체 정체가 뭐야? 맹세는 또 뭐고?","JPN":"レイ先輩！　先輩はいったい何者なの？　誓いってどういうこと？","ENG":"Ray! Who the heck are you, really? And what's this about an oath?","TWN":"雷伊前輩！你到底是誰？誓言又是什麼？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"정말 미카와 모두를 속이고 있었던 거야? 아카데미에 다니던 건 그저 장난이었어?","JPN":"本当にミカとみんなを騙していたの？\\nアカデミーに通っていたのは見せかけにすぎなかったの？","ENG":"Were you really lying to Mika and the rest of us? Was the Academy just a joke to you?","TWN":"你真的騙了米卡和所有人嗎？學院對你而言是個笑話嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……미안해, 미나 후배. 아니, 유미나님.","JPN":"……ごめんね、ミナ。いや、ヤナギ・ミナ様。","ENG":"I'm sorry, Mina. Or should I say, Ms. Yoo Mina.","TWN":"……抱歉，米娜後輩，不，是劉米娜。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"아카데미에서의 생활은 저에겐 꿈과도 같은 시간이었습니다.","JPN":"アカデミーでの生活は僕にとって夢のような時間でした。","ENG":"My time at the Academy was like a pleasant dream.","TWN":"在學院的生活，對我來說就好像做了一場夢。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 이젠…… 다른 꿈을 꿀 시간이에요.","JPN":"しかし今は……異なる夢をみる時間です。","ENG":"But now… it is time to dream of something else.","TWN":"只是……我現在要做其他的夢了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"전 제가 지키기로 맹세한 자들을 위해, 당신의 세계를 부술 겁니다.","JPN":"僕は自分が守ると誓った者たちのために、あなたの世界を滅ぼします。","ENG":"I've sworn an oath to protect my people… and thus I must destroy your world.","TWN":"為了我承諾過要守護的那些人，我必須毀掉你的世界。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"What's that supposed to mean?!","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그때까지, 최선을 다해 준비해 주세요.","JPN":"その時まで、最善を尽くして備えてください。","ENG":"I hope you'll do your best to prepare until then.","TWN":"在那之前，請盡可能地做好準備。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"당신이 준비되었을 때, 당신은 저와 만나게 될 겁니다.","JPN":"あなたが準備できた時、あなたは僕と会うことになるでしょう。","ENG":"When you are ready, we will meet again.","TWN":"等你準備好後，我們就會再相見。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그리고 제 소망을 이루기 위해, 당신을 죽이겠어요.","JPN":"そして僕の望みを叶えるために、あなたを殺します。","ENG":"And to fulfill my calling, I will kill you.","TWN":"另外，為了達成我的夢想，我會殺了你。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그럴 일은 없다.","JPN":"それはできない。","ENG":"It won't come to that.","TWN":"不可能。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"다음에 널 쓰러트리는 건 나일 테니까.","JPN":"次に君を倒すのは、この私だから。","ENG":"Because I'll take you down first.","TWN":"因為我下次就會打倒你。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"그럼 무운을 빕니다. 여러분.","JPN":"ではご武運を祈ります、みなさん。","ENG":"Well, then. Best of luck to you… everyone.","TWN":"那就祝你們好運了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};